    window.resetTile = function (id) {
      var tile = document.getElementById("tile-" + id);
      if (!tile) return;
      var isAfter = id.charAt(0) === "a";
      var sec = id === "awwc1" || id === "awb1" || id === "bwwc1" || id === "bwb1" ? "women" : "men";
      tile.className = "photo-tile " + (isAfter ? "after-tile" : "before-tile");
      (function (tid, ttype, tsec) { tile.onclick = function () { window.openCamera(tid, ttype, tsec); }; })(id, isAfter ? "after" : "before", sec);
      tile.innerHTML = '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="' + (isAfter ? "#22c55e" : "#f97316") + '" stroke-width="2" stroke-linecap="round"><path d="M23 19a2 2 0 01-2 2H3a2 2 0 01-2-2V8a2 2 0 012-2h4l2-3h6l2 3h4a2 2 0 012 2z"/><circle cx="12" cy="13" r="4"/></svg><div class="photo-tile-label">' + (labelMap[id] || id) + "</div>";
    };

